var removeDuplicates = function(nums) {
    let i = 0
    let j = 1

    while (j < nums.length) {
        if (nums[i] == nums[j]) {
            j++
        } else {
            nums[i + 1] = nums[j]
            i++
            j++
        }
    }

    return i + 1
};

